VALUES
  ('aboriginal-d0d1b9a2-moex-00038', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司以一部機器（帳面金額$320,000，公允價值$305,000）與乙公司交換一部公允價值$340,000 之機器；甲另支付現金$35,000。假設該交換具商業實質且公允價值能可靠衡量，則甲公司應認列 之交換損益為何？', '["$35,000利益", "$0", "$7,500損失", "$15,000損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00039', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X2年初以$5,400,000取得一部設備，耐用年限18年、無殘值，採直線法折舊，後續以 重估價模式衡量。X3年底進行重估，公允價值為$6,120,000；耐用年限與殘值均不變。公司政策 為重估增值於後續使用期間逐期轉入保留盈餘（不考慮所得稅）。試問X4年底「其他權益－重估 增值」之餘額為何？', '["$1,200,000", "$1,237,500", "$1,260,000", "$1,320,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00040', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X6年底並無列報無形資產，於X7年初取得乙公司控制權。合併當日，乙公司有正在執 行之三項可辨認且能可靠衡量之研發專案：', '["A專案：合併日公允價值$12,000；X7年間另投入$7,000，截至年底仍屬研究階段", "B專案：合併日公允價值$26,000；X7年間另投入$8,000，年末處於開發階段，未符合IAS38 第57段認列條件", "C專案：合併日公允價值$32,000；X7年間另投入$9,000，年末處於開發階段，已符合IAS38 第57段認列條件。 試問X7年底甲公司合併資產負債表應列示之無形資產合計為何？", "$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00041', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '下列四項中，有幾項不屬於投資性不動產？①目前尚未決定未來用途之建築物  ②出租予員工使', '["以融資租賃方式出租之不動產", "以營業租賃方式出租之辦公大樓", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00042', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '下列資產中，有幾項需要提列折舊？①已達可用狀態但尚未達經濟規模產出之設備  ②以公允價', '["以重估價模式衡量之建築物", "分類為待出售非流動資產的建 築物", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00043', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司自 X5 年起銷售一款新產品，提供兩年保固。依同業與本公司經驗，保固成本占銷貨收入 比率於出售後第一年估計為2.5%，出售後第二年估計為5.5%。X5與X6年度之銷貨與實際已支 付保固費用如下： X5年：銷貨$420,000；已發生保固支出$10,000 X6年：銷貨$560,000；已發生保固支出$22,000 試問截至X6年12月31日應列報之估計產品保固負債餘額為何？', '["$44,800", "$46,400", "$48,000", "$52,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00044', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X5年度的相關資料如下：本期稅後淨利$360,000；處分機器收現$240,000（其中包含出 售利益$80,000）；折舊費用$70,000；提列預期信用減損損失$30,000；應收帳款淨額增加$50,000。 請計算X5年度來自營業活動之現金流量為何？', '["$300,000", "$330,000", "$350,000", "$370,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00045', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-519af93a', 'sub-aboriginal-d0d1b9a2-03', NULL, 'essay', '請依預算法之相關規定詳述特種基金之意義、種類及審議為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "453c21baa5c8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
